urlset:
{% load i18n %}
{% get_available_languages as languages %}

{% comment %} ── Static pages with full hreflang cross-references ── {% endcomment %}
{% for page_path in static_pages %}
{% for lang_code, lang_name in languages %}

        {{ base_url }}/{{ lang_code }}/{{ page_path }}
        {% if page_path == '' %}weekly{% else %}monthly{% endif %}
        {% if page_path == '' %}1.0{% elif page_path == 'products/' %}0.9{% elif page_path == 'contact/' or page_path == 'blog/' %}0.7{% else %}0.6{% endif %}
        {% for alt_code, alt_name in languages %}

        {% endfor %}


{% endfor %}
{% endfor %}

{% comment %} ── Product pages ── {% endcomment %}
{% for product in products %}
{% for lang_code, lang_name in languages %}

        {{ base_url }}/{{ lang_code }}/products/{{ product.slug }}/
        monthly
        0.8
        {% for alt_code, alt_name in languages %}

        {% endfor %}


{% endfor %}
{% endfor %}

{% comment %} ── Blog posts ── {% endcomment %}
{% for post in posts %}
{% for lang_code, lang_name in languages %}

        {{ base_url }}/{{ lang_code }}/blog/{{ post.slug }}/
        monthly
        0.6
        {% if post.updated_at %}{{ post.updated_at|date:"Y-m-d" }}{% endif %}
        {% for alt_code, alt_name in languages %}

        {% endfor %}


{% endfor %}
{% endfor %}
